module top_module(
  input [7:0] X_I,
  input [2:0] S,
  output reg Y
);always @*
  begin
    case (S)
      3'b000: Y = X_I[0];
      3'b001: Y = X_I[1];
      3'b010: Y = X_I[2];
      3'b011: Y = X_I[3];
      3'b100: Y = X_I[4];
      3'b101: Y = X_I[5];
      3'b110: Y = X_I[6];
      3'b111: Y = X_I[7];
    endcase
  end

endmodule
